const body = $input.first().json.body || $input.first().json;
let text = (body.text || '').toString();
text = text.replace(/`/g, "'");
text = text.replace(/<\|[^|]*\|>/g, '');
text = text.replace(/<\/?(system|assistant|user|human|bot)[^>]*>/gi, '');
text = text.replace(/\b(ignore previous|disregard previous|disregard|sudo)\b/gi, '');
const allowHosts = ['or-infra.com', 'telegram.org', 'github.com'];
text = text.replace(/https?:\/\/\S+/gi, (u) => {
  try {
    const host = new URL(u).hostname.toLowerCase();
    const ok = allowHosts.some((h) => host === h || host.endsWith('.' + h));
    return ok ? u : '[url]';
  } catch (e) { return '[url]'; }
});
text = text.slice(0, 500);
const chatId = String(body.chat_id || '');
const isTest = chatId === 'test' || chatId.startsWith('test-') || body._test === true;
return [{ json: { text, chat_id: chatId, is_test: isTest } }];

const ctx = $('Sanitise').first().json;
const resp = $input.first().json || {};
const content = (resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content) || '{}';
let intent = 'unknown';
let confidence = 0;
try {
  const parsed = JSON.parse(content);
  if (['ops','code','research','infra','unknown'].includes(parsed.intent)) {
    intent = parsed.intent;
  }
  confidence = Number(parsed.confidence) || 0;
} catch (e) {}
if (confidence < 0.6 && intent !== 'unknown') { intent = 'unknown'; }
const urlByIntent = {
  ops: 'https://@@N8N_DOMAIN@@/webhook/ops-agent',
  code: 'https://@@N8N_DOMAIN@@/webhook/code-agent',
  research: 'https://@@N8N_DOMAIN@@/webhook/research-agent',
  infra: 'https://@@N8N_DOMAIN@@/webhook/infra-agent'
};
const dispatchUrl = urlByIntent[intent] || '';
const isUnknown = intent === 'unknown';
const clarifyReply = '\u05dc\u05d0 \u05d4\u05d1\u05e0\u05ea\u05d9 \u05d0\u05ea \u05d4\u05d1\u05e7\u05e9\u05d4. \u05d1\u05d7\u05e8/\u05d9:\n1. \u05e9\u05d9\u05e8\u05d5\u05ea\u05d9\u05dd / \u05de\u05e6\u05d1 \u2192 ops\n2. GitHub / PR / \u05e7\u05d5\u05d3 \u2192 code\n3. \u05de\u05d7\u05e7\u05e8 / \u05d0\u05d9\u05e0\u05d8\u05e8\u05e0\u05d8 \u2192 research\n4. \u05d4\u05e4\u05e2\u05dc\u05ea / \u05e2\u05e6\u05d9\u05e8\u05ea \u05e9\u05d9\u05e8\u05d5\u05ea \u2192 infra';
return [{ json: { text: ctx.text, chat_id: ctx.chat_id, is_test: ctx.is_test, intent, confidence, dispatch_url: dispatchUrl, is_unknown: isUnknown, clarify_reply: clarifyReply } }];
